SA1.sparql:
PREFIX epc: <http://tecnicasreunidas.es/ontology/epc#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

            SELECT ?worker ?cert WHERE {
                ?h a epc:CertificationHolding ;
                   epc:byWorker ?worker ;
                   epc:holdsCertification ?cert .
            }

ST1.sparql:
PREFIX epc: <http://tecnicasreunidas.es/ontology/epc#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

            SELECT ?worker ?cert WHERE {
                ?h a epc:CertificationHolding ;
                   epc:byWorker ?worker ;
                   epc:holdsCertification ?cert ;
                   epc:validFrom ?vf ;
                   epc:validTo   ?vt .
                FILTER("2024-07-01T00:00:00+00:00"^^xsd:dateTime >= ?vf)
                FILTER("2024-07-01T00:00:00+00:00"^^xsd:dateTime <= ?vt)
            }

SA2.sparql:
PREFIX epc: <http://tecnicasreunidas.es/ontology/epc#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

            SELECT ?worker ?permit ?cert WHERE {
                ?h a epc:CertificationHolding ;
                   epc:byWorker ?worker ;
                   epc:holdsCertification ?cert .
                ?req a epc:PermitCertRequirement ;
                     epc:forPermit ?permit ;
                     epc:requiresCertification ?cert .
            }

ST2.sparql:
PREFIX epc: <http://tecnicasreunidas.es/ontology/epc#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

            SELECT ?worker ?permit ?cert WHERE {
                ?h a epc:CertificationHolding ;
                   epc:byWorker ?worker ;
                   epc:holdsCertification ?cert ;
                   epc:validFrom ?hf ; epc:validTo ?ht .
                ?req a epc:PermitCertRequirement ;
                     epc:forPermit ?permit ;
                     epc:requiresCertification ?cert ;
                     epc:validFrom ?rf ; epc:validTo ?rt .
                FILTER("2024-07-01T00:00:00+00:00"^^xsd:dateTime >= ?hf && "2024-07-01T00:00:00+00:00"^^xsd:dateTime <= ?ht)
                FILTER("2024-07-01T00:00:00+00:00"^^xsd:dateTime >= ?rf && "2024-07-01T00:00:00+00:00"^^xsd:dateTime <= ?rt)
            }

