ST3_bitemporal.sparql:
PREFIX epc: <http://tecnicasreunidas.es/ontology/epc#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

            SELECT ?worker ?cert ?vf ?vt ?tx WHERE {
                ?h a epc:CertificationHolding ;
                   epc:byWorker ?worker ;
                   epc:holdsCertification ?cert ;
                   epc:validFrom ?vf ; epc:validTo ?vt ;
                   epc:txTime    ?tx .
                FILTER("2024-05-01T00:00:00+00:00"^^xsd:dateTime >= ?vf)
                FILTER("2024-05-01T00:00:00+00:00"^^xsd:dateTime <= ?vt)
                FILTER(?tx <= "2026-06-01T00:00:00+00:00"^^xsd:dateTime)
            }
